'use client';

import React, { useEffect, useRef } from 'react';
import { OmegaMessage } from './OmegaMessage';
import type { OmegaMessage as MessageType } from '../../hooks/useOmegaChat';

interface ChatViewProps {
  messages: MessageType[];
  isStreaming: boolean;
  systemState: 'idle' | 'thinking' | 'followup' | 'error';
  error?: string | null;
}

export function ChatView({
  messages,
  isStreaming,
  systemState,
  error,
}: ChatViewProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [messages, isStreaming]);

  return (
    <div className='flex-1 overflow-y-auto p-4 bg-white'>
      {messages.length === 0 ? (
        <div className='flex items-center justify-center h-full'>
          <div className='text-center text-gray-500'>
            <p className='text-lg font-semibold mb-2'>Start a conversation</p>
            <p className='text-sm'>Send a message or use voice mode</p>
          </div>
        </div>
      ) : (
        <div ref={containerRef} className='space-y-4'>
          {messages.map((msg) => (
            <OmegaMessage
              key={msg.id}
              role={msg.role}
              content={msg.content}
              timestamp={msg.createdAt}
            />
          ))}

          {systemState === 'thinking' && (
            <div className='flex gap-2 items-center text-gray-600'>
              <div className='flex gap-1'>
                <div className='w-2 h-2 bg-gray-400 rounded-full animate-bounce' />
                <div className='w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100' />
                <div className='w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200' />
              </div>
              <span className='text-sm'>OmegA is thinking...</span>
            </div>
          )}

          {systemState === 'error' && error && (
            <div className='bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded'>
              <p className='text-sm font-semibold'>Error</p>
              <p className='text-sm'>{error}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

