'use client';

import React from 'react';

interface SystemStateDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  state: {
    [key: string]: any;
  };
}

export function SystemStateDrawer({
  isOpen,
  onClose,
  state,
}: SystemStateDrawerProps) {
  if (!isOpen) return null;

  return (
    <div className='fixed inset-0 bg-black/30 z-40'>
      <div className='absolute right-0 top-0 bottom-0 w-80 bg-white shadow-lg overflow-y-auto'>
        <div className='sticky top-0 bg-white border-b border-gray-200 p-4 flex items-center justify-between'>
          <h3 className='font-semibold text-gray-900'>System State</h3>
          <button
            onClick={onClose}
            className='p-1 hover:bg-gray-100 rounded'
          >
            ✕
          </button>
        </div>

        <div className='p-4 space-y-4'>
          {Object.entries(state).map(([key, value]) => (
            <div key={key} className='border-b border-gray-200 pb-3'>
              <h4 className='text-xs font-semibold text-gray-500 uppercase mb-1'>
                {key}
              </h4>
              <pre className='text-xs bg-gray-50 p-2 rounded overflow-auto text-gray-700'>
                {JSON.stringify(value, null, 2)}
              </pre>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

